  const [
    savedScenarioAuditLog,
    setSavedScenarioAuditLog,
  ] = useState(() => {
    if (typeof window === "undefined") {
      return [];
    }

    try {
      const storedValue =
        window.localStorage.getItem(
          savedScenarioAuditStorageKey
        );

      const parsedValue = storedValue
        ? JSON.parse(storedValue)
        : [];

      if (!Array.isArray(parsedValue)) {
        return [];
      }

      const validEntries =
        parsedValue
          .filter(
            (entry) =>
              entry &&
              typeof entry ===
                "object" &&
              typeof entry.id ===
                "string" &&
              entry.id.trim()
                .length > 0 &&
              typeof entry.action ===
                "string" &&
              entry.action.trim()
                .length > 0 &&
              Number.isFinite(
                Date.parse(
                  String(
                    entry.occurred_at ??
                      ""
                  )
                )
              ) &&
              (
                entry.scenario_id ===
                  null ||
                (
                  typeof entry.scenario_id ===
                    "string" &&
                  entry.scenario_id.trim()
                    .length > 0
                )
              )
          )
          .map((entry) => ({
            id: String(entry.id).trim(),

            scenario_id:
              entry.scenario_id ===
              null
                ? null
                : String(
                    entry.scenario_id
                  ).trim(),

            scenario_name:
              typeof entry.scenario_name ===
              "string"
                ? entry.scenario_name
                : "",

            action: String(
              entry.action
            ).trim(),

            title:
              typeof entry.title ===
              "string"
                ? entry.title
                : "Scenario action",

            detail:
              typeof entry.detail ===
              "string"
                ? entry.detail
                : "",

            tone:
              typeof entry.tone ===
                "string" &&
              entry.tone.trim().length >
                0
                ? entry.tone
                : "#94a3b8",

            metadata:
              entry.metadata &&
              typeof entry.metadata ===
                "object" &&
              !Array.isArray(
                entry.metadata
              )
                ? entry.metadata
                : null,

            occurred_at: new Date(
              Date.parse(
                String(
                  entry.occurred_at
                )
              )
            ).toISOString(),
          }))
          .sort(
            (leftEntry, rightEntry) =>
              Date.parse(
                rightEntry.occurred_at
              ) -
              Date.parse(
                leftEntry.occurred_at
              )
          )
          .slice(
            0,
            maxSavedScenarioAuditEntries
          );

      return validEntries;
    } catch {
      return [];
    }
  });

