  const [
    savedScenarioAuditRestoreRollbackSnapshot,
    setSavedScenarioAuditRestoreRollbackSnapshot,
  ] = useState(() => {
    if (typeof window === "undefined") {
      return null;
    }

    const isPlainObject = (value) => {
      if (
        !value ||
        typeof value !== "object" ||
        Array.isArray(value)
      ) {
        return false;
      }

      const prototype =
        Object.getPrototypeOf(value);

      return (
        prototype === Object.prototype ||
        prototype === null
      );
    };

    const isValidSignature = (value) =>
      /^fnv1a-[0-9a-f]{8}$/i.test(
        String(value ?? "").trim()
      );

    const isValidCount = (value) => {
      const parsedValue = Number(value);
      return (
        Number.isFinite(parsedValue) &&
        parsedValue >= 0 &&
        Number.isInteger(parsedValue)
      );
    };

    try {
      const storedValue =
        window.localStorage.getItem(
          savedScenarioAuditRestoreRollbackStorageKey
        );

      const parsedValue = storedValue
        ? JSON.parse(storedValue)
        : null;

      if (!isPlainObject(parsedValue)) {
        return null;
      }

      if (
        parsedValue.schema !==
          PIP_STORAGE_SCHEMAS.scenarioAuditRestoreRollback.legacy ||
        !Number.isFinite(
          Date.parse(
            String(
              parsedValue.created_at ??
                ""
            )
          )
        ) ||
        !isValidSignature(
          parsedValue.source_archive_signature
        ) ||
        !isValidSignature(
          parsedValue.current_signature_before_restore
        ) ||
        !isValidSignature(
          parsedValue.expected_restored_signature
        ) ||
        !isValidCount(
          parsedValue.current_event_count_before_restore
        ) ||
        !isValidCount(
          parsedValue.expected_restored_event_count
        ) ||
        !Array.isArray(
          parsedValue.previous_audit_log
        ) ||
        !(
          parsedValue.previous_archive_receipt ===
            null ||
          parsedValue.previous_archive_receipt ===
            undefined ||
          isPlainObject(
            parsedValue.previous_archive_receipt
          )
        )
      ) {
        return null;
      }

      return {
        schema: parsedValue.schema,
        created_at: new Date(
          Date.parse(
            String(parsedValue.created_at)
          )
        ).toISOString(),
        source_archive_file:
          typeof parsedValue.source_archive_file ===
          "string"
            ? parsedValue.source_archive_file
            : "",
        source_archive_signature: String(
          parsedValue.source_archive_signature
        )
          .trim()
          .toLowerCase(),
        current_signature_before_restore:
          String(
            parsedValue.current_signature_before_restore
          )
            .trim()
            .toLowerCase(),
        current_event_count_before_restore:
          Number(
            parsedValue.current_event_count_before_restore
          ),
        expected_restored_signature:
          String(
            parsedValue.expected_restored_signature
          )
            .trim()
            .toLowerCase(),
        expected_restored_event_count:
          Number(
            parsedValue.expected_restored_event_count
          ),
        previous_audit_log:
          parsedValue.previous_audit_log.map(
            (entry) => ({
              ...entry,
            })
          ),
        previous_archive_receipt:
          parsedValue.previous_archive_receipt &&
          isPlainObject(
            parsedValue.previous_archive_receipt
          )
            ? {
                ...parsedValue.previous_archive_receipt,
              }
            : null,
      };
    } catch {
      return null;
    }
  });

  const [
    savedScenarioAuditRestoreReceipt,
    setSavedScenarioAuditRestoreReceipt,
  ] = useState(() => {
    if (typeof window === "undefined") {
      return null;
    }

    const isPlainObject = (value) => {
      if (
        !value ||
        typeof value !== "object" ||
        Array.isArray(value)
      ) {
        return false;
      }

      const prototype =
        Object.getPrototypeOf(value);

      return (
        prototype === Object.prototype ||
        prototype === null
      );
    };

    const supportedStatuses = new Set([
      "RESTORED",
      "ROLLED_BACK",
    ]);

    try {
      const storedValue =
        window.localStorage.getItem(
          savedScenarioAuditRestoreReceiptStorageKey
        );

      const parsedValue = storedValue
        ? JSON.parse(storedValue)
        : null;

      if (!isPlainObject(parsedValue)) {
        return null;
      }

      const parsedRestoredAt = Date.parse(
        String(
          parsedValue.restored_at ?? ""
        )
      );

      const parsedRolledBackAt = Date.parse(
        String(
          parsedValue.rolled_back_at ??
            ""
        )
      );

      const restoredEventCount = Number(
        parsedValue.restored_event_count
      );

      const previousEventCount = Number(
        parsedValue.previous_event_count
      );

      const rollbackAvailable =
        parsedValue.rollback_available === true ||
        parsedValue.rollback_available === false;

      if (
        parsedValue.schema !==
          PIP_STORAGE_SCHEMAS.scenarioAuditRestoreReceipt.legacy ||
        !supportedStatuses.has(
          String(
            parsedValue.status ?? ""
          )
        ) ||
        !Number.isFinite(parsedRestoredAt) ||
        typeof parsedValue.source_archive_file !==
          "string" ||
        typeof parsedValue.source_archive_signature !==
          "string" ||
        !Number.isFinite(restoredEventCount) ||
        restoredEventCount < 0 ||
        !Number.isInteger(restoredEventCount) ||
        !Number.isFinite(previousEventCount) ||
        previousEventCount < 0 ||
        !Number.isInteger(previousEventCount) ||
        !rollbackAvailable
      ) {
        return null;
      }

      return {
        schema: parsedValue.schema,
        status: String(
          parsedValue.status
        ),
        restored_at: new Date(
          parsedRestoredAt
        ).toISOString(),
        source_archive_file:
          parsedValue.source_archive_file,
        source_archive_signature: String(
          parsedValue.source_archive_signature
        )
          .trim()
          .toLowerCase(),
        restored_event_count:
          restoredEventCount,
        previous_event_count:
          previousEventCount,
        previous_signature:
          typeof parsedValue.previous_signature ===
          "string"
            ? parsedValue.previous_signature
            : null,
        matching_entry_id_count: Number(
          parsedValue.matching_entry_id_count ??
            0
        ),
        archive_only_entry_count: Number(
          parsedValue.archive_only_entry_count ?? 0
        ),
        current_only_entry_count: Number(
          parsedValue.current_only_entry_count ?? 0
        ),
        rollback_available:
          parsedValue.rollback_available,
        rollback_created_at:
          Number.isFinite(
            Date.parse(
              String(
                parsedValue.rollback_created_at ??
                  ""
              )
            )
          )
            ? new Date(
                Date.parse(
                  String(
                    parsedValue.rollback_created_at
                  )
                )
              ).toISOString()
            : null,
        rolled_back_at:
          Number.isFinite(parsedRolledBackAt)
            ? new Date(
                parsedRolledBackAt
              ).toISOString()
            : null,
      };
    } catch {
      return null;
    }
  });

