        if (!validation.valid) {
          throw new Error(
            validation.errors[0] ||
              "Scenario-library audit report validation failed."
          );
        }

        const escapeHtml = (value) =>
          String(value ?? "")
            .replace(/&/g, "&amp;")
            .replace(/</g, "&lt;")
            .replace(/>/g, "&gt;")
