  const exportPipProductionRunbook = () => {
    if (pipReleaseGateReport == null) {
      setPipReleaseGateRunbookExportStatus("failed");
      setPipReleaseGateLastError(
        "Runbook export requires a validated release-gate report."
      );
      return;
    }

    const reportValidation = validatePipReleaseGateReport(
      pipReleaseGateReport
    );
    if (reportValidation.valid !== true) {
      setPipReleaseGateRunbookExportStatus("failed");
      setPipReleaseGateLastError(
        reportValidation.errors?.[0] ??
          "Runbook export requires a valid release-gate report."
      );
      return;
    }

    try {
      const runbook = reportValidation.normalized.runbook;
      const sections = Array.isArray(runbook?.sections)
        ? runbook.sections
        : [];

      const lines = [
        "# Production Deployment Runbook (Diagnostic Only)",
        "",
        `Generated At: ${String(runbook?.generated_at ?? "")}`,
        "Executable Commands Included: NO",
        "",
      ];

      sections.forEach((section) => {
        lines.push(
          `## ${Number(section.sequence)}. ${String(
            section.title ?? ""
          )}`
        );
        lines.push("");
        lines.push(`Purpose: ${String(section.purpose ?? "")}`);
        lines.push("");
        lines.push("Manual Steps:");
        (Array.isArray(section.manual_steps)
          ? section.manual_steps
          : []
        ).forEach((step, index) => {
          lines.push(`${index + 1}. ${String(step ?? "")}`);
        });
        lines.push("");
      });

      const content = lines.join("\n");
      const blob = new Blob([content], {
        type: "text/markdown;charset=utf-8",
      });
      const objectUrl = window.URL.createObjectURL(blob);
      const link = document.createElement("a");
      link.href = objectUrl;
      link.download = `pip-production-runbook-${new Date()
        .toISOString()
        .replace(/[:.]/g, "-")}.md`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      window.URL.revokeObjectURL(objectUrl);
      setPipReleaseGateRunbookExportStatus("exported");
    } catch (error) {
      setPipReleaseGateRunbookExportStatus("failed");
      setPipReleaseGateLastError(
        error instanceof Error
          ? error.message
          : "Runbook export failed."
      );
    }
  };

