  const loadPipIncidentCasebook = async () => {
    if (
      !requirePermission(
        PIP_AUTHORIZATION_PERMISSIONS.AUDIT_MAINTAIN,
        "incident casebook"
      )
    ) {
      return;
    }

    if (readOnlyValidationMode) {
      setPipIncidentCasebookStatus("blocked");
      setPipIncidentCasebookLastError(
        "Batch 56C casebook retrieval is disabled for the non-production validation fixture."
      );
      return;
    }

    if (
      selectedConstituencyKey === "p999-validation" ||
      String(constituencyCode ?? "").trim().toUpperCase() === "P999"
    ) {
      setPipIncidentCasebookStatus("blocked");
      setPipIncidentCasebookLastError(
        "P999 remains read-only and cannot run Batch 56C operations."
      );
      return;
    }

    setPipIncidentCasebookStatus("loading");
    setPipIncidentCasebookLastError("");

    try {
      const signatureBefore = savedScenarioAuditArchiveSignature;
      const boundedLimit = normalizeBoundedIntegerInput(
        pipIncidentCasebookLimit,
        25,
        1,
        100
      );
      const response = await pipIncidentCasebookClient.listCases({
        targetEnvironment: pipDeploymentReadinessTarget,
        status:
          pipIncidentCasebookStatusFilter === "ALL"
            ? undefined
            : pipIncidentCasebookStatusFilter,
        severity:
          pipIncidentCasebookSeverityFilter === "ALL"
            ? undefined
            : pipIncidentCasebookSeverityFilter,
        limit: boundedLimit,
      });

      const reportValidation = validatePipIncidentCasebookReport(
        response?.data
      );

      if (reportValidation.valid !== true) {
        throw new Error(
          reportValidation.errors?.[0] ??
            "Incident casebook report validation failed."
        );
      }

      if (savedScenarioAuditArchiveSignature !== signatureBefore) {
        throw new Error(
          "Legacy scenario-audit browser-storage signature changed unexpectedly."
        );
      }

      const normalizedReport = reportValidation.normalized;
      const rows = Array.isArray(normalizedReport.cases)
        ? normalizedReport.cases
        : [];
      const selectedStillValid = rows.some(
        (entry) =>
          String(entry?.case_id ?? "") ===
          String(pipIncidentSelectedCaseId ?? "")
      );

      setPipIncidentCasebookReport(normalizedReport);
      setPipIncidentCasebookLimit(String(boundedLimit));
      setPipIncidentCasebookStatus(
        String(normalizedReport.status ?? "").toUpperCase() ===
          "EMPTY"
          ? "empty"
          : "ready"
      );
      setPipIncidentCasebookLastCheckedAt(new Date().toISOString());

      if (!selectedStillValid) {
        const firstCaseId = String(rows?.[0]?.case_id ?? "");
        setPipIncidentSelectedCaseId(firstCaseId);
        setPipIncidentSelectedCase(selectedStillValid ? pipIncidentSelectedCase : null);
      }
    } catch (error) {
      setPipIncidentCasebookStatus("failed");
      setPipIncidentCasebookLastError(
        error instanceof Error
          ? error.message
          : "Failed to load incident casebook."
      );
    }
  };

  const loadPipIncidentCase = async () => {
    const caseId = String(pipIncidentSelectedCaseId ?? "").trim();
    if (!caseId) {
      setPipIncidentCasebookStatus("failed");
      setPipIncidentCasebookLastError("Select an incident case before loading.");
      return;
    }

    setPipIncidentCasebookStatus("loading_case");
    setPipIncidentCasebookLastError("");

    try {
      const response = await pipIncidentCasebookClient.getCase({ caseId });
      const caseValidation = validatePipIncidentCase(response?.data);

      if (caseValidation.valid !== true) {
        throw new Error(
          caseValidation.errors?.[0] ??
            "Incident case validation failed."
        );
      }

      const normalizedCase = caseValidation.normalized;
      const draft = {};
      (normalizedCase?.checklist?.items ?? []).forEach((entry) => {
        const key = String(entry?.item_id ?? "");
        if (!key) {
          return;
        }
        draft[key] = {
          status: String(entry?.status ?? PIP_INCIDENT_CHECKLIST_STATUSES.PENDING),
          safeNote: String(entry?.safe_note ?? ""),
          evidenceReference: String(entry?.evidence_reference ?? ""),
        };
      });

      setPipIncidentChecklistDraft(draft);
      setPipIncidentSelectedCase(normalizedCase);
      setPipIncidentClosureEvidence(
        normalizedCase?.closure?.closure_evidence_generated === true
          ? pipIncidentClosureEvidence
          : null
      );
      setPipIncidentCasebookStatus("ready");
      setPipIncidentCasebookLastCheckedAt(new Date().toISOString());
    } catch (error) {
      setPipIncidentCasebookStatus("failed");
      setPipIncidentCasebookLastError(
        error instanceof Error
          ? error.message
          : "Failed to load selected incident case."
      );
    }
  };

  const createPipIncidentCase = async () => {
    if (
      !requirePermission(
        PIP_AUTHORIZATION_PERMISSIONS.AUDIT_MAINTAIN,
        "incident case creation"
      )
    ) {
      return;
    }

    const titleValidation = sanitizePipIncidentSafeText(
      pipIncidentCaseTitle,
      {
        field: "title",
        maxLength: 120,
        required: true,
      }
    );
    const summaryValidation = sanitizePipIncidentSafeText(
      pipIncidentCaseSummary,
      {
        field: "safe_summary",
        maxLength: 600,
        required: true,
      }
    );

    if (titleValidation.valid !== true || summaryValidation.valid !== true) {
      setPipIncidentCasebookStatus("failed");
      setPipIncidentCasebookLastError(
        titleValidation.errors?.[0] ??
          summaryValidation.errors?.[0] ??
          "Incident case safe text validation failed."
      );
      return;
    }

    if (
      !Object.values(PIP_INCIDENT_CASE_SEVERITIES).includes(
        String(pipIncidentCaseSeverity ?? "").toUpperCase()
      )
    ) {
      setPipIncidentCasebookStatus("failed");
      setPipIncidentCasebookLastError("Incident case severity is invalid.");
      return;
    }

    const selectedEvidence = Array.isArray(pipIncidentEvidenceSelection)
      ? pipIncidentEvidenceSelection
      : [];

    const snapshotIds = selectedEvidence
      .filter((entry) => String(entry ?? "").startsWith("SNAPSHOT:"))
      .map((entry) => String(entry).replace("SNAPSHOT:", ""))
      .filter(Boolean);
    const timelineEventIds = selectedEvidence
      .filter((entry) => String(entry ?? "").startsWith("TIMELINE:"))
      .map((entry) => String(entry).replace("TIMELINE:", ""))
      .filter(Boolean);

    if (snapshotIds.length === 0 && timelineEventIds.length === 0) {
      setPipIncidentCasebookStatus("failed");
      setPipIncidentCasebookLastError(
        "Select at least one sanitized evidence reference."
      );
      return;
    }

    setPipIncidentCasebookStatus("creating");
    setPipIncidentCasebookLastError("");

    try {
      const signatureBefore = savedScenarioAuditArchiveSignature;
      const response = await pipIncidentCasebookClient.createCase({
        targetEnvironment: pipDeploymentReadinessTarget,
        constituencyKey: "p134",
        parliamentCode: "P134",
        severity: String(pipIncidentCaseSeverity ?? "").toUpperCase(),
        title: titleValidation.normalized,
        safeSummary: summaryValidation.normalized,
        snapshotIds,
        timelineEventIds,
      });

      const receiptValidation = validatePipIncidentCaseMutationReceipt(
        response?.data?.receipt
      );
      const caseValidation = validatePipIncidentCase(
        response?.data?.case
      );

      if (receiptValidation.valid !== true || caseValidation.valid !== true) {
        throw new Error(
          receiptValidation.errors?.[0] ??
            caseValidation.errors?.[0] ??
            "Incident case create response validation failed."
        );
      }

      if (
        receiptValidation.normalized.durable_write_verified !== true ||
        receiptValidation.normalized.durable_readback_verified !== true ||
        receiptValidation.normalized.audit_write_verified !== true ||
        receiptValidation.normalized.audit_readback_verified !== true
      ) {
        throw new Error(
          "Incident case create durability or audit readback verification failed."
        );
      }

      if (savedScenarioAuditArchiveSignature !== signatureBefore) {
        throw new Error(
          "Legacy scenario-audit browser-storage signature changed unexpectedly."
        );
      }

      setPipIncidentCaseTitle("");
      setPipIncidentCaseSummary("");
      setPipIncidentCaseSeverity(PIP_INCIDENT_CASE_SEVERITIES.WARNING);
      setPipIncidentEvidenceSelection([]);
      setPipIncidentSelectedCase(caseValidation.normalized);
      setPipIncidentSelectedCaseId(String(caseValidation.normalized.case_id ?? ""));
      setPipIncidentCasebookStatus("ready");
      await loadPipIncidentCasebook();
    } catch (error) {
      setPipIncidentCasebookStatus("failed");
      setPipIncidentCasebookLastError(
        error instanceof Error
          ? error.message
          : "Failed to create incident case."
      );
    }
  };

  const updatePipIncidentChecklist = async (itemId) => {
    const caseId = String(pipIncidentSelectedCase?.case_id ?? "").trim();
    if (!caseId) {
      setPipIncidentCasebookStatus("failed");
      setPipIncidentCasebookLastError("Load a selected case before checklist updates.");
      return;
    }

    if (
      String(pipIncidentSelectedCase?.status ?? "").toUpperCase() ===
      PIP_INCIDENT_CASE_STATUSES.CLOSED
    ) {
      setPipIncidentCasebookStatus("failed");
      setPipIncidentCasebookLastError("Closed cases cannot be updated.");
      return;
    }

    const targetItemId = String(itemId ?? "").trim();
    const draft = pipIncidentChecklistDraft?.[targetItemId] ?? {};
    const nextStatus = String(draft?.status ?? "").trim().toUpperCase();
    const safeNoteValidation = sanitizePipIncidentSafeText(
      draft?.safeNote,
      {
        field: "checklist.safe_note",
        maxLength: 300,
        required: false,
      }
    );

    if (
      !Object.values(PIP_INCIDENT_CHECKLIST_STATUSES).includes(nextStatus)
    ) {
      setPipIncidentCasebookStatus("failed");
      setPipIncidentCasebookLastError("Checklist status is invalid.");
      return;
    }

    if (safeNoteValidation.valid !== true) {
      setPipIncidentCasebookStatus("failed");
      setPipIncidentCasebookLastError(
        safeNoteValidation.errors?.[0] ?? "Checklist safe note is invalid."
      );
      return;
    }

    setPipIncidentCasebookStatus("updating_checklist");
    setPipIncidentCasebookLastError("");

    try {
      const signatureBefore = savedScenarioAuditArchiveSignature;
      const response = await pipIncidentCasebookClient.updateChecklist({
        caseId,
        targetEnvironment: pipDeploymentReadinessTarget,
        constituencyKey: "p134",
        parliamentCode: "P134",
        itemId: targetItemId,
        status: nextStatus,
        safeNote: safeNoteValidation.normalized,
        evidenceReference: String(draft?.evidenceReference ?? "").trim(),
      });

      const receiptValidation = validatePipIncidentCaseMutationReceipt(
        response?.data?.receipt
      );
      const caseValidation = validatePipIncidentCase(
        response?.data?.case
      );

      if (receiptValidation.valid !== true || caseValidation.valid !== true) {
        throw new Error(
          receiptValidation.errors?.[0] ??
            caseValidation.errors?.[0] ??
            "Incident checklist update validation failed."
        );
      }

      if (savedScenarioAuditArchiveSignature !== signatureBefore) {
        throw new Error(
          "Legacy scenario-audit browser-storage signature changed unexpectedly."
        );
      }

      setPipIncidentSelectedCase(caseValidation.normalized);
      setPipIncidentCasebookStatus("ready");
      setPipIncidentCasebookLastCheckedAt(new Date().toISOString());
    } catch (error) {
      setPipIncidentCasebookStatus("failed");
      setPipIncidentCasebookLastError(
        error instanceof Error
          ? error.message
          : "Failed to update incident checklist item."
      );
    }
  };

  const closePipIncidentCase = async () => {
    const caseId = String(pipIncidentSelectedCase?.case_id ?? "").trim();
    if (!caseId) {
      setPipIncidentCasebookStatus("failed");
      setPipIncidentCasebookLastError("Load a selected case before closure.");
      return;
    }

    if (
      String(pipIncidentSelectedCase?.status ?? "").toUpperCase() !==
      PIP_INCIDENT_CASE_STATUSES.READY_FOR_CLOSURE
    ) {
      setPipIncidentCasebookStatus("failed");
      setPipIncidentCasebookLastError(
        "Incident case must be READY_FOR_CLOSURE before closure."
      );
      return;
    }

    if (pipIncidentClosureAcknowledged !== true) {
      setPipIncidentCasebookStatus("failed");
      setPipIncidentCasebookLastError(
        "Manual closure acknowledgement is required."
      );
      return;
    }

    const closureSummaryValidation = sanitizePipIncidentSafeText(
      pipIncidentClosureSummary,
      {
        field: "closure_summary",
        maxLength: 600,
        required: true,
      }
    );

    if (closureSummaryValidation.valid !== true) {
      setPipIncidentCasebookStatus("failed");
      setPipIncidentCasebookLastError(
        closureSummaryValidation.errors?.[0] ??
          "Closure summary is invalid."
      );
      return;
    }

    setPipIncidentCasebookStatus("closing");
    setPipIncidentCasebookLastError("");

    try {
      const signatureBefore = savedScenarioAuditArchiveSignature;
      const response = await pipIncidentCasebookClient.closeCase({
        caseId,
        targetEnvironment: pipDeploymentReadinessTarget,
        constituencyKey: "p134",
        parliamentCode: "P134",
        closureOutcome: pipIncidentClosureOutcome,
        closureSummary: closureSummaryValidation.normalized,
        closureAcknowledged: true,
      });

      const receiptValidation = validatePipIncidentCaseMutationReceipt(
        response?.data?.receipt
      );
      const caseValidation = validatePipIncidentCase(
        response?.data?.case
      );
      const evidenceValidation = validatePipIncidentClosureEvidence(
        response?.data?.closure_evidence
      );

      if (
        receiptValidation.valid !== true ||
        caseValidation.valid !== true ||
        evidenceValidation.valid !== true
      ) {
        throw new Error(
          receiptValidation.errors?.[0] ??
            caseValidation.errors?.[0] ??
            evidenceValidation.errors?.[0] ??
            "Incident closure validation failed."
        );
      }

      if (
        receiptValidation.normalized.durable_write_verified !== true ||
        receiptValidation.normalized.durable_readback_verified !== true ||
        receiptValidation.normalized.audit_write_verified !== true ||
        receiptValidation.normalized.audit_readback_verified !== true
      ) {
        throw new Error(
          "Incident closure durability or audit readback verification failed."
        );
      }

      if (savedScenarioAuditArchiveSignature !== signatureBefore) {
        throw new Error(
          "Legacy scenario-audit browser-storage signature changed unexpectedly."
        );
      }

      setPipIncidentSelectedCase(caseValidation.normalized);
      setPipIncidentClosureEvidence(evidenceValidation.normalized);
      setPipIncidentCasebookStatus("ready");
      setPipIncidentCasebookLastCheckedAt(new Date().toISOString());
    } catch (error) {
      setPipIncidentCasebookStatus("failed");
      setPipIncidentCasebookLastError(
        error instanceof Error
          ? error.message
          : "Failed to close incident case."
      );
    }
  };

