  const inspectPipCentralRepository = async () => {
    if (
      !requirePermission(
        PIP_AUTHORIZATION_PERMISSIONS.AUDIT_MAINTAIN,
        "central repository inspection"
      )
    ) {
      return;
    }

    if (readOnlyValidationMode) {
      setPipCentralRepositoryStatus("blocked");
      setPipCentralRepositoryLastError(
        "Central repository inspection is disabled for the non-production validation fixture."
      );
      return;
    }

    if (
      selectedConstituencyKey === "p999-validation" ||
      String(constituencyCode ?? "").trim().toUpperCase() === "P999"
    ) {
      setPipCentralRepositoryStatus("blocked");
      setPipCentralRepositoryLastError(
        "P999 remains read-only and cannot inspect repository abstraction controls."
      );
      return;
    }

    setPipCentralRepositoryStatus("loading");
    setPipCentralRepositoryLastError("");

    try {
      const signatureBefore = savedScenarioAuditArchiveSignature;
      const response =
        await pipCentralRepositoryClient.inspectRepository();

      const reportValidation = validatePipCentralRepositoryReport(
        response?.data
      );

      if (reportValidation.valid !== true) {
        throw new Error(
          reportValidation.errors?.[0] ??
            "Central repository report validation failed."
        );
      }

      const report = reportValidation.normalized;

      if (
        String(report.active_repository_kind ?? "") !==
          PIP_CENTRAL_REPOSITORY_KINDS.DURABLE_FILE ||
        report.active_repository_authoritative !== true ||
        report.production_database_configured !== false ||
        report.production_database_connection_attempted !== false ||
        report.production_database_read_enabled !== false ||
        report.production_database_write_enabled !== false ||
        report.repository_cutover_enabled !== false ||
        report.dual_write_enabled !== false ||
        report.shadow_write_enabled !== false ||
        report.automatic_synchronisation_enabled !== false ||
        report.automatic_schema_migration_enabled !== false ||
        report.automatic_data_migration_enabled !== false ||
        report.automatic_failover_enabled !== false
      ) {
        throw new Error(
          "Central repository inspection invariants were not satisfied."
        );
      }

      const signatureAfter =
        createSavedScenarioAuditArchiveSignature(
          savedScenarioAuditLog
        );
      const storageMutationObserved =
        signatureAfter !== signatureBefore;

      setPipCentralRepositoryReport(report);
      setPipCentralRepositoryStatus(
        String(report.status ?? "").toUpperCase() ===
          PIP_CENTRAL_REPOSITORY_STATUSES.READY
          ? "ready"
          : "failed"
      );
      setPipCentralRepositoryLastCheckedAt(
        new Date().toISOString()
      );
      setPipCentralRepositoryJsonExportStatus("idle");
      if (storageMutationObserved) {
        setPipCentralRepositoryLastError(
          "Central repository inspection completed, but protected browser storage changed during inspection window."
        );
      }
    } catch (error) {
      setPipCentralRepositoryStatus("failed");
      setPipCentralRepositoryLastError(
        error instanceof Error
          ? error.message
          : "Central repository inspection failed."
      );
    }
  };

