      setPipSecretReferenceBindingReport(validation.normalized);
      setPipSecretReferenceBindingAcceptanceReceipt(null);
      setPipSecretReferenceBindingStatus("inspected");
      setPipSecretReferenceBindingLastCheckedAt(new Date().toISOString());
      setPipSecretReferenceBindingJsonExportStatus("idle");
