  const resetPipRuntimeAcceptanceState = () => {
    setPipRuntimeAcceptanceStatus("idle");
    setPipRuntimeAcceptanceReport(null);
    setPipRuntimeAcceptanceLastCheckedAt(null);
    setPipRuntimeAcceptanceLastError("");
    setPipRuntimeAcceptanceJsonExportStatus("idle");
  };

  const hydratePipRuntimeDependencyState = async () => {
    const constituencyKey = selectedConstituencyKey;
    const parliamentCode = String(constituencyCode ?? "")
      .trim()
      .toUpperCase();

    try {
      const registryResult =
        await pipProductionDatabaseReferenceRegistryClient.inspectReferenceRegistry(
          {
            constituencyKey,
            parliamentCode,
          }
        );

      const snapshotValidation =
        validatePipDatabaseReferenceSlotRegistrySnapshot(
          registryResult?.data
        );

      if (snapshotValidation.valid === true) {
        const normalizedSnapshot = snapshotValidation.normalized;
        setPipDatabaseReferenceRegistrySnapshot(normalizedSnapshot);
        setPipDatabaseReferenceRegistryStatus("inspected");

        const complete =
          String(normalizedSnapshot.registry_status ?? "")
            .trim()
            .toUpperCase() ===
          PIP_DATABASE_REFERENCE_REGISTRY_STATUSES.COMPLETE;

        const completenessCandidate = {
          schema: PIP_DATABASE_REFERENCE_COMPLETENESS_SCHEMA,
          verification_id:
            String(normalizedSnapshot.registry_id ?? "") ||
            `runtime-hydration-${Date.now()}`,
          verification_signature:
            String(normalizedSnapshot.registry_signature ?? "") ||
            "runtime-hydration",
          verified_at: new Date().toISOString(),
          registry_id: String(normalizedSnapshot.registry_id ?? ""),
          registry_signature: String(
            normalizedSnapshot.registry_signature ?? ""
          ),
          status: complete
            ? PIP_DATABASE_REFERENCE_REGISTRY_STATUSES.VERIFIED_COMPLETE
            : PIP_DATABASE_REFERENCE_REGISTRY_STATUSES.VERIFIED_INCOMPLETE,
          required_slot_count: Number(
            normalizedSnapshot.required_slot_count ?? 0
          ),
          registered_slot_count: Number(
            normalizedSnapshot.registered_slot_count ?? 0
          ),
          missing_slot_count: Number(normalizedSnapshot.missing_slot_count ?? 0),
          missing_slot_keys: Array.isArray(normalizedSnapshot.missing_slot_keys)
            ? normalizedSnapshot.missing_slot_keys
            : [],
          registered_slot_keys: Array.isArray(
            normalizedSnapshot.registered_slot_keys
          )
            ? normalizedSnapshot.registered_slot_keys
            : [],
          registration_mutation_performed: false,
          secret_reference_values_excluded: true,
          secret_reference_names_excluded: true,
          environment_variable_names_excluded: true,
          connection_values_excluded: true,
          credential_values_excluded: true,
          database_driver_invoked: false,
          database_adapter_invoked: false,
          network_resolution_invoked: false,
          sql_execution_invoked: false,
          central_repository_modified: false,
          browser_storage_modified: false,
          p999_write_protection: true,
        };

        const completenessValidation =
          validatePipDatabaseReferenceCompletenessReport(
            completenessCandidate
          );

        if (completenessValidation.valid === true) {
          setPipDatabaseReferenceRegistryCompletenessReport(
            completenessValidation.normalized
          );
          setPipDatabaseReferenceRegistryCompletenessStatus("inspected");
        }
      }
    } catch {
      // Preserve pending state when durable evidence is unavailable.
    }

    try {
      const bindingResult =
        await pipProductionDatabaseBindingReadinessClient.inspectBindingReadiness(
          {
            constituencyKey,
            parliamentCode,
          }
        );

      const readinessValidation = validatePipDatabaseBindingReadinessReport(
        bindingResult?.data
      );

      if (readinessValidation.valid === true) {
        const normalizedReadiness = readinessValidation.normalized;
        setPipDatabaseBindingReadinessReport(normalizedReadiness);
        setPipDatabaseBindingReadinessStatus("inspected");

        const handoffReceiptCandidate = {
          schema: PIP_DATABASE_BINDING_HANDOFF_ACKNOWLEDGEMENT_SCHEMA,
          acknowledgement_id: String(
            normalizedReadiness.acknowledgement_id ?? ""
          ),
          acknowledgement_signature:
            String(normalizedReadiness.readiness_signature ?? "") ||
            "runtime-hydration-signature",
          acknowledged_at:
            normalizedReadiness.acknowledged_at || new Date().toISOString(),
          readiness_id: String(normalizedReadiness.readiness_id ?? ""),
          readiness_signature: String(
            normalizedReadiness.readiness_signature ?? ""
          ),
          binding_ready: normalizedReadiness.binding_ready === true,
          operator_handoff_state:
            normalizedReadiness.operator_handoff_state,
          operator_handoff_acknowledged:
            normalizedReadiness.operator_handoff_acknowledged === true,
          changed: false,
          result_code: "NO_CHANGE",
          p999_write_protection: true,
          active_repository_kind: "DURABLE_FILE",
          durable_file_authoritative: true,
          secret_reference_values_excluded: true,
          secret_reference_names_excluded: true,
          environment_variable_names_excluded: true,
          connection_values_excluded: true,
          credential_values_excluded: true,
          database_driver_invoked: false,
          database_adapter_invoked: false,
          network_resolution_invoked: false,
          sql_execution_invoked: false,
          binding_activation_performed: false,
          binding_mutation_performed: false,
          central_repository_modified: false,
          browser_storage_modified: false,
        };

        const handoffValidation =
          validatePipDatabaseBindingHandoffAcknowledgement(
            handoffReceiptCandidate
          );

        if (handoffValidation.valid === true) {
          setPipDatabaseBindingHandoffAcknowledgement(
            handoffValidation.normalized
          );
          setPipDatabaseBindingHandoffStatus("acknowledged");
        }
      }
    } catch {
      // Preserve pending state when durable evidence is unavailable.
    }

    try {
      const providerResult =
        await pipDeploymentSecretProviderAdapterClient.getReport();

      const providerValidation = validatePipSecretProviderAdapterReport(
        providerResult?.report
      );

      if (providerValidation.valid === true) {
        const normalizedProvider = providerValidation.normalized;
        setPipDeploymentSecretProviderAdapterReport(normalizedProvider);
        setPipDeploymentSecretProviderAdapterStatus("inspected");

        if (providerResult?.report?.acknowledgement?.acknowledged === true) {
          const providerReceiptValidation =
            validatePipSecretProviderAdapterAcceptanceReceipt(
              buildPipSecretProviderAdapterAcceptanceReceipt({
                generatedAt: normalizedProvider.generated_at,
                changed: false,
                resultCode: "NO_CHANGE",
                report: normalizedProvider,
              })
            );

          if (providerReceiptValidation.valid === true) {
            setPipDeploymentSecretProviderAdapterAcceptanceReceipt(
              providerReceiptValidation.normalized
            );
            setPipDeploymentSecretProviderAdapterStatus("acknowledged");
          }
        }
      }
    } catch {
      // Preserve pending state when durable evidence is unavailable.
    }

    try {
      const bindingResult =
        await pipDeploymentSecretReferenceBindingClient.getReport();

      const bindingValidation = validatePipSecretReferenceBindingReport(
        bindingResult?.report
      );

      if (bindingValidation.valid === true) {
        const normalizedBinding = bindingValidation.normalized;
        setPipSecretReferenceBindingReport(normalizedBinding);
        setPipSecretReferenceBindingStatus("inspected");

        if (bindingResult?.report?.acknowledgement?.acknowledged === true) {
          const receiptValidation =
            validatePipSecretReferenceBindingAcceptanceReceipt(
              buildPipSecretReferenceBindingAcceptanceReceipt({
                generated_at: normalizedBinding.generated_at,
                acknowledged_at:
                  bindingResult?.report?.acknowledgement?.acknowledged_at,
                result_code: "NO_CHANGE",
                acknowledgement_changed: false,
                report: normalizedBinding,
              })
            );

          if (receiptValidation.valid === true) {
            setPipSecretReferenceBindingAcceptanceReceipt(
              receiptValidation.normalized
            );
            setPipSecretReferenceBindingStatus("acknowledged");
          }
        }
      }
    } catch {
      // Preserve pending state when durable evidence is unavailable.
    }
  };

  const checkPipRuntimeApiHealth = async () => {
    if (
      !requirePermission(
        PIP_AUTHORIZATION_PERMISSIONS.AUDIT_MAINTAIN,
        "runtime acceptance API health check"
      )
    ) {
      return;
    }

    setPipRuntimeAcceptanceStatus("checking_api");
    setPipRuntimeAcceptanceLastError("");

    try {
      const healthResult = await pipRuntimeAcceptanceClient.getHealth();
      const healthSafe = isPlainObject(healthResult?.data)
        ? healthResult.data
        : {};

      setPipSystemHealthReport(healthSafe);
      setPipRuntimeAcceptanceStatus("idle");
      setPipRuntimeAcceptanceLastCheckedAt(new Date().toISOString());
    } catch (error) {
      setPipRuntimeAcceptanceStatus(
        PIP_RUNTIME_ACCEPTANCE_STATUSES.API_UNAVAILABLE
      );
      setPipRuntimeAcceptanceLastError(
        error instanceof Error
          ? error.message
          : "Runtime API health check failed."
      );
      setPipRuntimeAcceptanceLastCheckedAt(new Date().toISOString());
    }
  };

