  const duplicateSavedComparisonScenario = () => {
    if (
      !requirePermission(
        PIP_AUTHORIZATION_PERMISSIONS.SCENARIO_CREATE,
        "scenario duplicate"
      )
    ) {
      return;
    }

    try {
      if (!selectedSavedComparisonScenario) {
        throw new Error(
          "No saved comparison scenario selected."
        );
      }

      if (
        savedComparisonScenarios.length >=
        maxSavedComparisonScenarios
      ) {
        throw new Error(
          `The saved-scenario library is full at ${maxSavedComparisonScenarios} scenarios. Export a backup and delete an existing scenario before duplicating.`
        );
      }

      const existingNames = new Set(
        savedComparisonScenarios.map(
          (scenario) =>
            String(scenario.name)
              .trim()
              .toLowerCase()
        )
      );

      const buildDuplicateName = (
        sourceName,
        suffix
      ) => {
        const availableSourceLength =
          Math.max(
            1,
            60 - suffix.length - 1
          );

        const normalizedSourceName =
          String(sourceName)
          .trim()
          .slice(
            0,
            availableSourceLength
          );

        return `${normalizedSourceName} ${suffix}`.trim();
      };

      const baseScenarioName =
        String(
          selectedSavedComparisonScenario.name
        )
          .trim()
          .replace(
            /\sCopy(?:\s\d+)?$/i,
            ""
          );

      let copyNumber = 1;

      let duplicateName =
        buildDuplicateName(
          baseScenarioName,
          "Copy"
        );

      while (
        existingNames.has(
          duplicateName.toLowerCase()
        )
      ) {
        copyNumber += 1;

        duplicateName =
          buildDuplicateName(
            baseScenarioName,
            `Copy ${copyNumber}`
          );
      }

      const duplicatedAt =
        new Date().toISOString();

      const duplicationCorrelationId =
        `pip-governance-correlation-${
          typeof window !==
            "undefined" &&
          window.crypto?.randomUUID
            ? window.crypto.randomUUID()
            : `${Date.now()}-${Math.random()
                .toString(36)
                .slice(2, 10)}`
        }`;

      const duplicateScenarioId =
        typeof window !== "undefined" &&
        window.crypto?.randomUUID
          ? `p134-comparison-${window.crypto.randomUUID()}`
          : `p134-comparison-${Date.now()}-${Math.random()
              .toString(36)
              .slice(2, 8)}`;

      const duplicateScenario = {
        ...selectedSavedComparisonScenario,

        id: duplicateScenarioId,

        name: duplicateName,

        pinned: false,
        pinned_at: null,

        locality_keys: [
          ...selectedSavedComparisonScenario.locality_keys,
        ].slice(0, maximumComparisonLocalities),

        duplicated_from_scenario_id:
          selectedSavedComparisonScenario.id,

        duplicated_from_scenario_name:
          selectedSavedComparisonScenario.name,

        duplicated_at:
          duplicatedAt,

        created_at: duplicatedAt,
        updated_at: duplicatedAt,
      };

      setSavedComparisonScenarios(
        (currentScenarios) =>
          [
            duplicateScenario,

            ...currentScenarios,
          ].slice(
            0,
            maxSavedComparisonScenarios
          )
      );

      setSelectedSavedScenarioId(
        duplicateScenarioId
      );

      recordSavedScenarioAudit({
        scenarioId:
          selectedSavedComparisonScenario.id,

        scenarioName:
          selectedSavedComparisonScenario.name,

        action: "DUPLICATED",
        title: "Scenario duplicated",

        detail:
          `Created duplicate "${duplicateName}".`,

        tone: "#34d399",

        metadata: {
          duplicate_scenario_id:
            duplicateScenarioId,
          duplicate_name:
            duplicateName,

          source_scenario_id:
            selectedSavedComparisonScenario.id,
          source_name:
            selectedSavedComparisonScenario.name,

          governance: {
            relationship_only: true,
          },
        },

        eventCategory:
          "MODIFICATION",

        operation:
          "DUPLICATE_SOURCE",

        beforeScenario:
          selectedSavedComparisonScenario,

        afterScenario:
          selectedSavedComparisonScenario,

        correlationId:
          duplicationCorrelationId,

        sourceContext:
          "SCENARIO_MANAGER",

        occurredAt:
          duplicatedAt,
      });

      recordSavedScenarioAudit({
        scenarioId:
          duplicateScenarioId,

        scenarioName:
          duplicateName,

        action:
          "DUPLICATED_FROM",

        title:
          "Created from another scenario",

        detail:
          `Duplicated from "${selectedSavedComparisonScenario.name}".`,

        tone: "#34d399",

        metadata: {
          source_scenario_id:
            selectedSavedComparisonScenario.id,
          source_name:
            selectedSavedComparisonScenario.name,

          duplicate_scenario_id:
            duplicateScenarioId,
          duplicate_name:
            duplicateName,
        },

        eventCategory:
          "CREATION",

        operation:
          "DUPLICATE_CREATE",

        beforeScenario: null,

        afterScenario:
          duplicateScenario,

        correlationId:
          duplicationCorrelationId,

        sourceContext:
          "SCENARIO_MANAGER",

        occurredAt:
          duplicatedAt,
      });

      setSavedScenarioDuplicateStatus(
        "duplicated"
      );

      window.setTimeout(() => {
        setSavedScenarioDuplicateStatus(
          "idle"
        );
      }, 1800);
    } catch (error) {
      setSavedScenarioDuplicateStatus(
        "failed"
      );

      window.alert(
        error instanceof Error
          ? error.message
          : "Unable to duplicate the saved scenario."
      );

      window.setTimeout(() => {
        setSavedScenarioDuplicateStatus(
          "idle"
        );
      }, 1800);
    }
  };

